fn verify_jwt<T: serde::de::DeserializeOwned>(
    token_str: &str,
    secret_key_base64: &str,
    valid_algs: &[jsonwebtoken::Algorithm],
) -> Result<T, jsonwebtoken::errors::Error> {
    use jsonwebtoken::{decode, decode_header, DecodingKey, Validation};

    let header = decode_header(token_str)?;
    let alg = header.alg;

    if !valid_algs.contains(&alg) {
        return Err(jsonwebtoken::errors::ErrorKind::InvalidAlgorithm.into());
    }

    let decoding_key = DecodingKey::from_base64_secret(secret_key_base64)?;

    let mut validation = Validation::new(alg);
    validation.algorithms = valid_algs.to_vec();
    validation.validate_exp = true; // Validate expiration claim (exp)
    validation.validate_nbf = true; // Validate not before claim (nbf)
    // Add any other specific validation rules as needed, e.g., validation.aud, validation.iss

    let token_data = decode::<T>(token_str, &decoding_key, &validation)?;

    Ok(token_data.claims)
}

